#include <bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=3e5+5;
char s[1001][1001];
int n,m,sx,sy,ex,ey,st,ed;
vector<PII> g[MAXN];
int dis[MAXN],vis[MAXN];
struct node
{
    int d,u;
    bool operator<(const node &a)const
    {
        return d>a.d;
    }
};
void dij()
{
    priority_queue<node> q;
    FOR(i,0,n*m)dis[i]=llinf;
    cl(vis);
    dis[st]=0;
    q.push({0,st});
    wh(!q.empty())
    {
        node x=q.top();q.pop();
        int u=x.u;
        if(vis[u])continue;
        vis[u]=1;
        FOI(e,g[u])
        {
            int v=e.fst,w=e.snd;
            if(dis[v]>dis[u]+w)
            {
                dis[v]=dis[u]+w;
                q.push({dis[v],v});
            }
        }
    }
}
signed main()
{
    wh(1)
    {
        n=read();m=read();
        if(n==0&&m==0)return 0;
        FOR(i,0,n*m)g[i].clear();
        FOR(i,1,n)scanf("%s",s[i]+1);
        FOR(i,1,n)FOR(j,1,m)
        {
            int u=(i-1)*m+j;
            if(i>1)g[u].pb(mk((i-2)*m+j,s[i][j]!=s[i-1][j]));
            if(i<n)g[u].pb(mk(i*m+j,s[i][j]!=s[i+1][j]));
            if(j>1)g[u].pb(mk((i-1)*m+j-1,s[i][j]!=s[i][j-1]));
            if(j<m)g[u].pb(mk((i-1)*m+j+1,s[i][j]!=s[i][j+1]));
        }
        sx=read();sy=read();ex=read();ey=read();
        sy++;ey++;
        st=sx*m+sy;
        ed=ex*m+ey;
        dij();
        writeln(dis[ed]);
    }
}
